/**
 * Scaffolds dashboard directory and CI workflow in a consuming project.
 */

import { mkdirSync, writeFileSync, copyFileSync, existsSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));

export function scaffold({ platform, cwd = process.cwd() }) {
  const dashboardDir = join(cwd, 'dashboard');
  const dataDir = join(dashboardDir, 'data');

  // Create dashboard structure
  mkdirSync(dataDir, { recursive: true });

  // Copy index.html
  const indexSrc = join(__dirname, '..', 'dashboard', 'index.html');
  const indexDest = join(dashboardDir, 'index.html');
  if (existsSync(indexSrc)) {
    copyFileSync(indexSrc, indexDest);
  } else {
    writeFileSync(indexDest, '<!DOCTYPE html><html><body>Dashboard placeholder</body></html>');
  }

  // Write empty history
  writeFileSync(join(dataDir, 'history.json'), '[]');

  // Copy workflow template
  const templateFile = platform === 'github' ? 'github-workflow.yml' : 'forgejo-workflow.yml';
  const workflowDir = platform === 'github'
    ? join(cwd, '.github', 'workflows')
    : join(cwd, '.forgejo', 'workflows');

  mkdirSync(workflowDir, { recursive: true });
  copyFileSync(
    join(__dirname, '..', 'templates', templateFile),
    join(workflowDir, 'e2e-dashboard.yml')
  );

  console.log(`Scaffolded e2e-dashboard for ${platform}:`);
  console.log(`  dashboard/index.html`);
  console.log(`  dashboard/data/history.json`);
  console.log(`  ${platform === 'github' ? '.github' : '.forgejo'}/workflows/e2e-dashboard.yml`);
}
